            long long water_end = water_start + waterDuration[j];
            long long total_time = water_end;
            if (total_time < min_time) {
                min_time = total_time;
            }

            // Case 2: water first, then land
            water_start = waterStartTime[j];
            water_end = water_start + waterDuration[j];
            land_start = max(landStartTime[i], water_end);
            land_end = land_start + landDuration[i];
            total_time = land_end;
            if (total_time < min_time) {
                min_time = total_time;
            }
        }
    }

    return min_time;
